//\n//  MainListView.swift\n//  DeviceRadar\n//\n//  Created by DeviceRadar Team.\n//  Copyright © 2026 LethalLethes. All rights reserved.\n//\n\nimport SwiftUI\n\n/// Main list view displaying all signal categories and filters.\nstruct MainListView: View {\n    @ObservedObject var viewModel: RadarViewModel\n    \n    var body: some View {\n        List {\n            // Statistics pills\n            Section {\n                HStack(spacing: 10) {\n                    StatPillView(\n                        value: viewModel.count(for: .passive),\n                        label: \"Passiv\",\n                        color: Tier.passive.color\n                    )\n                    StatPillView(\n                        value: viewModel.count(for: .permissioned),\n                        label: \"İcazəli\",\n                        color: Tier.permissioned.color\n                    )\n                    StatPillView(\n                        value: viewModel.count(for: .advanced),\n                        label: \"Gizli\",\n                        color: Tier.advanced.color\n                    )\n                }\n                .listRowBackground(Color.clear)\n                .listRowInsets(EdgeInsets())\n            }\n            \n            // Tier filters\n            Section {\n                ScrollView(.horizontal, showsIndicators: false) {\n                    HStack(spacing: 8) {\n                        FilterChipView(\n                            label: \"Hamisı\",\n                            icon: \"square.grid.2x2\",\n                            color: .primary,\n                            isSelected: viewModel.selectedTier == nil\n                        ) {\n                            viewModel.selectedTier = nil\n                        }\n                        \n                        ForEach(Tier.allCases, id: \\.self) { tier in\n                            FilterChipView(\n                                label: tier.rawValue,\n                                icon: tier.icon,\n                                color: tier.color,\n                                isSelected: viewModel.selectedTier == tier\n                            ) {\n                                if viewModel.selectedTier == tier {\n                                    viewModel.selectedTier = nil\n                                } else {\n                                    viewModel.selectedTier = tier\n                                }\n                            }\n                        }\n                    }\n                    .padding(.vertical, 4)\n                }\n                .listRowBackground(Color.clear)\n                .listRowInsets(EdgeInsets())\n            }\n            \n            // Category sections\n            ForEach(viewModel.filtered) { category in\n                CategorySectionView(category: category)\n            }\n            \n            // Timestamp\n            Section {\n                Text(\"Tarix: \\(viewModel.generatedAt)\")\n                    .font(.caption2)\n                    .foregroundColor(.secondary)\n                    .frame(maxWidth: .infinity, alignment: .center)\n                    .listRowBackground(Color.clear)\n            }\n        }\n        .listStyle(.insetGrouped)\n    }\n}\n\n// MARK: - Preview\n\n#if DEBUG\nstruct MainListView_Previews: PreviewProvider {\n    static var previews: some View {\n        let vm = RadarViewModel()\n        return MainListView(viewModel: vm)\n    }\n}\n#endif\n